import { colors } from '@fs/zion-ui'
import { line } from 'd3-shape'
import { select } from 'd3-selection'

/* istanbul ignore file */

/**
 * RelationshipViewerD3
 * Manages ancillary calculating and drawing of connector lines. Excluded from coverage, because having it covered would not actually provide any piece of mind for elements that need to be verified visually.
 */

// d3 DRAWING FUNCTIONALITY:

/**
 * Given an element, return the points that correspond to the middle of the north, south, east, and west of the element.
 * @param {HTMLElement} canvas - The svg canvas to draw on.
 * @param {HTMLElement} el - The HTML element to calculate connection points for.
 * @param {Function} getBoundingRect - Passthrough of ZoomPan.getBoundingRect, which is needed to take matrix transformation into account when determining true element position.
 * @returns {object} - An object containing the centered reference points for each cardinal direction.
 */
function calculateConnectionPoints(canvas, el, getBoundingRect) {
  const elRect = getBoundingRect(el)

  // Since the element and the canvas show up in the same space on the screen, we just need to adjust the coordinates of the element for where the canvas starts since the rect we get back is relative to the viewport.
  const canvasRect = getBoundingRect(canvas)
  const left = elRect.left - canvasRect.left
  const top = elRect.top - canvasRect.top
  const centerX = left + elRect.width / 2
  const centerY = top + elRect.height / 2
  const northBits = { x: centerX, y: top }
  const southBits = { x: centerX, y: top + elRect.height }
  const eastBits = { x: left + elRect.width, y: centerY }
  const westBits = { x: left, y: centerY }

  return {
    north: northBits,
    south: southBits,
    east: eastBits,
    west: westBits,
  }
}

function calculateCenterXCoordinate(start, end) {
  const centerX = start.x + (end.x - start.x) / 2
  return { x: centerX, y: start.y }
}

/**
 * Given a start point and an end point, draw a line on the specified canvas.
 * @param {object} startPoint - X,Y coordinates of where to draw the line from.
 * @param {object} endPoint - X,Y coordinates of where to draw the line to.
 * @param {HTMLElement} canvas - The svg canvas to draw on.
 * @returns {undefined} - Draws directly on the provided svg canvas.
 */
function drawConnectorLine(startPoint, endPoint, canvas) {
  if (startPoint && endPoint) {
    const points = [
      [startPoint.x, startPoint.y],
      [endPoint.x, endPoint.y],
    ]

    // Add intermediate points to draw through, if elements are not aligned in the X axis
    if (startPoint.x !== endPoint.x) {
      const splitTheYDifference = startPoint.y + Math.abs(startPoint.y - endPoint.y) / 2
      points.splice(1, 0, [startPoint.x, splitTheYDifference])
      points.splice(2, 0, [endPoint.x, splitTheYDifference])
    }

    // console.log(points.toString())

    const pathData = line()(points)

    canvas
      .append('path')
      .attr('d', pathData)
      .attr('fill', 'none')
      .attr('stroke', colors.gray100)
      .attr('stroke-width', 2)
  }
}

/**
 * Determine if we need to draw connector lines, and do it, if necessary.
 * @param {HTMLAllCollection} generations - List of generations to draw lines between.
 * @param {HTMLElement} canvas - The svg canvas to draw on.
 * @param {Function} getBoundingRect - Passthrough of ZoomPan.getBoundingRect, which is needed to take matrix transformation into account when determining true element position.
 * @param {Boolean} accessibleRelationshipViewerIsOn - If the feature flag for using the accessible version of generations
 */
export default function drawAllConnectorLines(generations, canvas, getBoundingRect) {
  const d3Canvas = select(canvas).html(null) // .html(null) clears the canvas before drawing
  for (let i = 0; i < generations.length; i++) {
    const currentGeneration = generations[i]

    // TODO: Handle relationshipToPrevious = "CLOSE_RELATIVE", which will only have a single generation with an ascending and a descending person, NO apex
    // special handling for when we are related through a spouse only
    const apexNode = currentGeneration.querySelector(
      '[type="apex"] [inpath]:not([targetperson]) [data-testid="person"]'
    )
    const apexTargetPersonSpouse = currentGeneration.querySelector(
      '[type="apex"] [inpath][targetperson] [data-testid="person"]'
    )
    const targetPersonSpouse = currentGeneration.querySelector(
      '[type="descending"] [inpath][targetperson] [data-testid="person"]'
    )
    const descendingNodePerson = currentGeneration.querySelector(
      '[type="descending"] [inpath]:not([targetperson]) [data-testid="person"]'
    )
    const initialPersonSpouse = currentGeneration.querySelector(
      '[type="ascending"][coparentispathperson] [inpath]:not([initial]) [data-testid="person"]'
    )
    const initialPerson = currentGeneration.querySelector(
      '[type="ascending"][coparentispathperson] [inpath][initial] [data-testid="person"]'
    )
    // if we have related spouses in our path, connect to them
    if (
      (apexNode || descendingNodePerson || initialPerson) &&
      (apexTargetPersonSpouse || targetPersonSpouse || initialPersonSpouse)
    ) {
      if (descendingNodePerson && targetPersonSpouse) {
        const startPoint = calculateConnectionPoints(canvas, descendingNodePerson, getBoundingRect).east
        const endPoint = calculateConnectionPoints(canvas, targetPersonSpouse, getBoundingRect).west
        endPoint.y = startPoint.y
        drawConnectorLine(startPoint, endPoint, d3Canvas)
      }
      if (initialPerson && initialPersonSpouse) {
        const startPoint = calculateConnectionPoints(canvas, initialPerson, getBoundingRect).east
        const endPoint = calculateConnectionPoints(canvas, initialPersonSpouse, getBoundingRect).west
        endPoint.y = startPoint.y
        drawConnectorLine(startPoint, endPoint, d3Canvas)
      }
      if (apexNode && apexTargetPersonSpouse) {
        // Find RTL layout by checking if the target spouse is positioned to the left of the main person
        const apexRect = getBoundingRect(apexNode)
        const spouseRect = getBoundingRect(apexTargetPersonSpouse)
        const isRTL = spouseRect.left < apexRect.left
        // In RTL, spouse is on left, so connect from apex west to spouse east
        // In LTR, spouse is on right, so connect from apex east to spouse west
        const startPoint = calculateConnectionPoints(canvas, apexNode, getBoundingRect)[isRTL ? 'west' : 'east']
        const endPoint = calculateConnectionPoints(canvas, apexTargetPersonSpouse, getBoundingRect)[
          isRTL ? 'east' : 'west'
        ]
        endPoint.y = startPoint.y
        drawConnectorLine(startPoint, endPoint, d3Canvas)
      }
    }

    // Check if there is a next generation to draw lines between
    let ascendingNode
    let descendingNode
    let nextAscendingNode
    let nextDescendingNode
    if (generations[i + 1]) {
      const nextGeneration = generations[i + 1]

      // Find the correct node to potentially connect to - we start at the top and draw the lines going down
      ascendingNode = currentGeneration.querySelector(
        '[type="ascending"] [inpath]:not([targetperson]):not([coparentispathperson]) [data-testid="person"]'
      )
      descendingNode = currentGeneration.querySelector(
        '[type="descending"] [inpath]:not([targetperson]) [data-testid="person"]'
      )
      nextAscendingNode = nextGeneration.querySelector(
        '[type="ascending"] [inpath]:not([targetperson]) [data-testid="person"]'
      )
      nextDescendingNode = nextGeneration.querySelector(
        '[type="descending"] [inpath]:not([targetperson]) [data-testid="person"]'
      )
    }
    let startPoint
    let endPoint

    // If there is an ascending node above us, connect to it
    if (ascendingNode && nextAscendingNode) {
      startPoint = calculateConnectionPoints(canvas, nextAscendingNode, getBoundingRect).south
      endPoint = calculateConnectionPoints(canvas, ascendingNode, getBoundingRect).north
      drawConnectorLine(startPoint, endPoint, d3Canvas)
    }

    // If there is a descending node below us, connect to it
    if (descendingNode && nextDescendingNode) {
      startPoint = calculateConnectionPoints(canvas, descendingNode, getBoundingRect).south
      endPoint = calculateConnectionPoints(canvas, nextDescendingNode, getBoundingRect).north
      drawConnectorLine(startPoint, endPoint, d3Canvas)
    }

    // draw apex T's and connect them to the descenders
    if (apexNode) {
      const sourceCoParent = currentGeneration.querySelector('[type="apex"] [sourcecoparent] [data-testid="person"]')
      const destCoParent = currentGeneration.querySelector('[type="apex"] [destcoparent] [data-testid="person"]')
      const commonCoParent = currentGeneration.querySelector(
        '[type="apex"] [coparent]:not([targetperson]) [data-testid="person"]'
      )
      const apexConnectionPoints = calculateConnectionPoints(canvas, apexNode, getBoundingRect)

      if (destCoParent) {
        // draw horizontal line
        startPoint = apexConnectionPoints.east
        endPoint = calculateConnectionPoints(canvas, destCoParent, getBoundingRect).west
        endPoint.y = startPoint.y
        drawConnectorLine(startPoint, endPoint, d3Canvas)
        // draw vertical line out of horizontal line to go down to the bottom of the node
        startPoint = calculateCenterXCoordinate(startPoint, endPoint)
        endPoint = { x: startPoint.x, y: apexConnectionPoints.south.y }
        drawConnectorLine(startPoint, endPoint, d3Canvas)
        // draw vertical line out of vertical line
        startPoint = endPoint
        endPoint = calculateConnectionPoints(canvas, nextDescendingNode, getBoundingRect).north
        drawConnectorLine(startPoint, endPoint, d3Canvas)
      }

      if (sourceCoParent) {
        // draw horizontal line
        startPoint = apexConnectionPoints.west
        endPoint = calculateConnectionPoints(canvas, sourceCoParent, getBoundingRect).east
        endPoint.y = startPoint.y
        drawConnectorLine(startPoint, endPoint, d3Canvas)
        // draw vertical line out of horizontal line to go down to the bottom of the node
        startPoint = calculateCenterXCoordinate(startPoint, endPoint)
        endPoint = { x: startPoint.x, y: apexConnectionPoints.south.y }
        drawConnectorLine(startPoint, endPoint, d3Canvas)
        // draw vertical line out of vertical line
        startPoint = endPoint
        if (generations[i - 1]) {
          const previousAscendingNode = generations[i - 1].querySelector(
            '[type="ascending"] [inpath]:not([targetperson]):not([coparentispathperson]) [data-testid="person"]'
          )
          endPoint = calculateConnectionPoints(canvas, previousAscendingNode, getBoundingRect).north
        }
        drawConnectorLine(startPoint, endPoint, d3Canvas)
      }

      if (commonCoParent) {
        // draw horizontal line
        const coparentConnectionPoints = calculateConnectionPoints(canvas, commonCoParent, getBoundingRect)
        const coParentIsEastOfApexNode = apexConnectionPoints.west.x < coparentConnectionPoints.west.x
        startPoint = coParentIsEastOfApexNode ? apexConnectionPoints.east : coparentConnectionPoints.east
        endPoint = coParentIsEastOfApexNode ? coparentConnectionPoints.west : apexConnectionPoints.west
        endPoint.y = startPoint.y
        drawConnectorLine(startPoint, endPoint, d3Canvas)
        // draw vertical line out of horizontal line to go down to the bottom of the node
        startPoint = calculateCenterXCoordinate(startPoint, endPoint)
        endPoint = { x: startPoint.x, y: apexConnectionPoints.south.y }
        drawConnectorLine(startPoint, endPoint, d3Canvas)
        // draw vertical line out of vertical line
        startPoint = endPoint

        if (generations[i - 1]) {
          const previousAscendingNode = generations[i - 1].querySelector(
            '[type="ascending"] [inpath]:not([targetperson]):not([coparentispathperson]) [data-testid="person"]'
          )
          if (previousAscendingNode) {
            endPoint = calculateConnectionPoints(canvas, previousAscendingNode, getBoundingRect).north
            drawConnectorLine(startPoint, endPoint, d3Canvas)
          }
        }
        if (nextDescendingNode) {
          endPoint = calculateConnectionPoints(canvas, nextDescendingNode, getBoundingRect).north
          drawConnectorLine(startPoint, endPoint, d3Canvas)
        }
      }
    }
  }
}
