import React, { useEffect, useState, useRef, useCallback, useMemo } from 'react'
import { css } from '@linaria/core'
import { trackEvent } from '@fs/zion-analytics'
import debounce from 'lodash.debounce'
import { boolAttr } from '@fs/zion-frontend-friends'
import { ControlView, NoticeLoading } from '@fs/zion-icon'
import { FullPageOverlay, ZoomPanControlButton, ZoomPan, useZoomPan, colors, usePageWidth } from '@fs/zion-ui'
import { getPreference, setPreference } from '@fs/zion-preferences'
import { useTranslation } from 'react-i18next'
import { useHelpOverlayAction } from '@fs/zion-help-overlay'
import drawAllConnectorLines from './RelationshipViewerD3'
import { RelationshipViewerContext } from './RelationshipViewerContext'
import RelationshipViewerCouple, { personNodeWidth } from './RelationshipViewerCouple'
import useRelationship from './useRelationshipHook'
import NoRelationshipDisplay from './NoRelationshipDisplay'

const backgroundColorWrapper = css`
  background-color: ${colors.gray03};
  height: 100%;
  width: 100%;
`

const connectorLines = css`
  inset-inline-start: 0;
  height: 100%;
  position: absolute;
  top: 0;
  width: 100%;
`

const loadingSpinnerWrapper = css`
  position: fixed;
  inset-inline-start: calc(50% - 30px);
  top: calc(50% - 30px);
`

const generationsWrapper = css`
  position: relative;
  margin: 0 auto;
  width: fit-content;

  /* We handle showing a spouse that we are related to when other spouses are not showing by positioning it absolutely - we need to add the extra padding here so things display properly */
  /* special case when the apex contains the related person as a spouse when showing spouses to keep all the ascending people beneath the root couple */
  &[target-person-is-spouse][show-spouses][empty-descending-side],
  &[target-person-is-spouse]:not([show-spouses]) {
    padding-inline-end: ${personNodeWidth}px;
  }
  &[related-through-initial-spouse]:not([show-spouses]) {
    padding-inline-start: ${personNodeWidth}px;
  }
`

const relationshipWrapperCss = css`
  position: relative;
  width: fit-content;
  opacity: 0; /* we set this to 1 manually during the open animation */
`

const gridCss = css`
  display: grid;
  grid-template-columns: var(--generations-grid-columns);
  gap: var(--generations-grid-gap);
`

const generationsCss = css`
  justify-self: center;
  align-self: start;
`

// TODO: fix this!!!!! it used to be inside the toggle wrapper & > div section
/* elevate(2) */

const minZoom = 0.25
const maxZoom = 15

const calcAnimationPan = ({ size, totalSize, position }) => (position + size / 2) / totalSize
const calcAnimationZoom = ({ targetNode, stage }) => {
  const xRatio = targetNode.offsetWidth / stage.offsetWidth
  const yRatio = targetNode.offsetHeight / stage.offsetHeight
  // The inverse average ratio scaled by fourth of the maxZoom
  // this results in "as big as we can get while keeping the target in bounds"
  return (1 - (xRatio + yRatio) / 2) * (maxZoom / 4)
}

// Call the function that determines if we need to draw connector lines, and does it, if necessary
const drawConnectorLines = (controllerRef) => {
  const canvas = document.getElementById('svg-canvas-for-relationship-connector-lines')
  const generations = document.querySelectorAll('[data-testid^="generation"]')
  const controller = controllerRef.current
  const getBoundingRect = controller?.getBoundingRect.bind(controller)
  drawAllConnectorLines(generations, canvas, getBoundingRect)
}

// it starts with the user view focused on the target person, then zooms out to show the whole path.
const openAnimation = debounce(
  ({ targetNode, zoomPanRef, stage, relationshipWrapper, controllerRef }) => {
    const values = {
      zoom: calcAnimationZoom({ targetNode, stage }),
      panX: calcAnimationPan({
        size: targetNode.offsetWidth,
        totalSize: stage.offsetWidth,
        // the generation row and the couple wrapper add to the true X offset of this element
        position:
          targetNode.offsetLeft +
          targetNode.parentElement.offsetLeft +
          targetNode.parentElement.parentElement.offsetLeft,
      }),
      panY: calcAnimationPan({
        size: targetNode.offsetHeight,
        totalSize: stage.offsetHeight,
        // the generation row and the couple wrapper add to the true Y offset of this element
        position:
          targetNode.offsetTop + targetNode.parentElement.offsetTop + targetNode.parentElement.parentElement.offsetTop,
      }),
    }
    zoomPanRef.current.set(values, false)
    setTimeout(() => {
      // This needs to happen after we have stopped animating and before we start animating again to avoid problems with the lines being in the wrong spot. This fixes a bug where in ios the lines sometimes don't show up at all.
      drawConnectorLines(controllerRef)
      relationshipWrapper.style.opacity = 1 // show the contents now that they are done rendering
      setTimeout(() => zoomPanRef.current.reset(), 1000)
    }, 750)
  },
  15,
  { leading: false, trailing: true }
)

/**
 * Presentational relationship viewer.
 *
 * @param {object} props - See RelationshipViewer docs.
 * @returns {HTMLElement} - JSX.
 */
function PassiveRelationshipViewer(props = {}) {
  const { overlay, relationshipData, disallowSpouses, noLinks } = props
  const [t] = useTranslation()
  const isNotSmallScreen = usePageWidth()({ sm: true })
  const noRelationshipTitle = t('relationship-viewer.relationship-unknown')
  const errorWithRelationshipTitle = t('relationship-viewer.error-getting-relationship-title')

  const showSpousesPrefName = 'tree.relationshipViewer.showSpouses'
  const [showSpouses, setShowSpouses] = useState(false)
  const [preferenceFetched, setPreferenceFetched] = useState(false)
  const subtitleRef = useRef()

  const relationshipWrapperRef = useRef()

  // In order to animate the opening, we need to pass around a ref to zoomPan so that it does not get closed over
  const [zoomPanRefs, zoomPan] = useZoomPan()
  const zoomPanRef = useRef()
  zoomPanRef.current = zoomPan

  // zoompan hardcore breaks if the height or width is ever zero
  const [stageHeight, setStageHeight] = useState(1)
  const [stageWidth, setStageWidth] = useState(1)

  const toPersonName = relationshipData?.targetPerson?.nameConclusion?.details?.fullText

  let relationshipTitle = toPersonName
    ? t('relationship-viewer.relationship-title', { toPersonName })
    : t('relationship-viewer.relationship-loading-title')

  relationshipTitle = relationshipData?.noRelationship ? noRelationshipTitle : relationshipTitle
  relationshipTitle = relationshipData?.errorWithRelationship ? errorWithRelationshipTitle : relationshipTitle
  relationshipTitle = relationshipData?.userHasNotOptedIn ? errorWithRelationshipTitle : relationshipTitle

  // in the case of close relative, the initial/final generation will also be the first generation, and it is not an apex type generation, so the ascending and descending sides are not empty
  const emptyAscendingSide =
    relationshipData?.generations &&
    relationshipData?.generations[0]?.initialGeneration &&
    relationshipData?.generations[0]?.apex
  const emptyDescendingSide =
    relationshipData?.generations &&
    relationshipData?.generations[0]?.finalGeneration &&
    relationshipData?.generations[0]?.apex
  const closeRelative =
    relationshipData?.generations && relationshipData.generations[0] && !relationshipData.generations[0].apex
  const targetPersonIsSpouse = ['SPOUSE', 'HUSBAND', 'WIFE'].includes(
    relationshipData?.targetPerson?.relationshipToPrevious
  )
  const initialGeneration = relationshipData?.generations?.find((gen) => gen.initialGeneration)
  const relatedThroughInitialSpouse =
    initialGeneration?.ascendingSide?.coParentIsPathPerson || initialGeneration?.descendingSide?.coParentIsPathPerson

  const handleToggle = () => {
    if (disallowSpouses) return null
    trackEvent({ event_name: 'toggle_show_spouses' })
    const show = !showSpouses
    setShowSpouses(show)
    setPreference(showSpousesPrefName, show)
    zoomPan.reset()
    return show
  }

  // TODO: we need to remove this when we get the ability to programatically set the position outside the bounds for the open animation.
  const panMarginX = useCallback(({ viewerRef }) => (viewerRef?.current?.clientWidth ?? 0) / 2, [])
  const panMarginY = useCallback(({ viewerRef }) => (viewerRef?.current?.clientHeight ?? 0) / 2, [])

  // set height and width when the data we are displaying changes because zoomPan needs the height and width.
  useEffect(() => {
    if (relationshipData?.generations && preferenceFetched) {
      drawConnectorLines(zoomPanRefs.controllerRef)
    }

    const { offsetHeight, offsetWidth } = relationshipWrapperRef.current || {}
    // zoompan hardcore breaks if the height or width is ever zero, so we intentionally account for if it is zero or undefined here
    if (offsetHeight && offsetWidth) {
      setStageHeight(offsetHeight)
      setStageWidth(offsetWidth)
    }
    // preferenceFetched is in the dep array because we need something async to trigger a re-render
    // because we rely on person nodes to be in the DOM to draw connector lines, and to set the height and width
  }, [
    relationshipData,
    showSpouses,
    preferenceFetched,
    zoomPanRefs?.controllerRef,
    relationshipWrapperRef.current?.offsetHeight,
  ])

  // fire off the opening animation
  useEffect(() => {
    if (relationshipWrapperRef.current) {
      const targetNode = relationshipWrapperRef.current.querySelector('[data-testid~="target"]')
      if (targetNode) {
        openAnimation({
          targetNode,
          zoomPanRef,
          stage: zoomPanRefs?.stageRef.current,
          relationshipWrapper: relationshipWrapperRef.current,
          controllerRef: zoomPanRefs.controllerRef,
        })
      }
    }
    // preferenceFetched is in the dep array because we need something async to trigger a re-render
    // because we rely on the whole thing to be rendered before we can run the animation
  }, [relationshipData, zoomPanRefs?.stageRef, preferenceFetched, zoomPanRefs?.controllerRef])

  // get the preference for whether or not to show spouses
  useEffect(() => {
    let current = true
    getPreference(showSpousesPrefName)
      .then((pref) => {
        if (!current) return null
        !disallowSpouses && setShowSpouses(pref)
        setPreferenceFetched(true)
        return pref
      })
      .catch((err) => {
        if (!current) return
        console.error('RelationshipViewer:getPreference', err)
        setPreferenceFetched(true)
      })
    return () => {
      current = false
    }
  }, [disallowSpouses])

  const value = useMemo(() => ({ insideRelationshipViewer: true }), [])

  const showSpouseLabel = showSpouses
    ? t('relationship-viewer.hide-spouses-button.label')
    : t('relationship-viewer.show-spouses-button.label')

  const helpOverlayAction = useHelpOverlayAction({ helpActionUrl: '/tree/relationship-viewer/' })

  return (
    <RelationshipViewerContext.Provider value={value}>
      <FullPageOverlay
        id="relationship-viewer"
        data-testid="relationship-viewer"
        title={relationshipTitle}
        actions={[
          helpOverlayAction,
          !isNotSmallScreen &&
            !disallowSpouses && {
              onClick: handleToggle,
              label: showSpouseLabel,
            },
        ]}
        subtitle={
          relationshipData?.relationshipDescription && (
            <span data-testid="relationship-viewer-subtitle" tabIndex={-1} ref={subtitleRef}>
              {relationshipData?.relationshipDescription}
            </span>
          )
        }
        focusRef={relationshipData?.relationshipDescription && subtitleRef}
        {...overlay}
      >
        {/* This wrapper div is to standardize the background color to always match the zoom-pan color */}
        <div className={backgroundColorWrapper}>
          {/* Loading Spinner */}
          {((!toPersonName && !relationshipData?.noRelationship && !relationshipData?.errorWithRelationship) ||
            !preferenceFetched) && (
            <div className={loadingSpinnerWrapper}>
              <NoticeLoading size="lg" />
            </div>
          )}
          {/* ZoomPan with relationship viewer */}
          {relationshipData?.generations && (
            <ZoomPan
              {...zoomPanRefs}
              minZoom={minZoom}
              maxZoom={maxZoom}
              stageRight={stageWidth}
              stageBottom={stageHeight}
              imageMode
              panMarginX={panMarginX}
              panMarginY={panMarginY}
              controls={
                <>
                  {preferenceFetched && relationshipData?.generations && !disallowSpouses && isNotSmallScreen && (
                    <ZoomPanControlButton
                      data-testid="show-spouses"
                      expanded
                      label={showSpouseLabel}
                      Icon={ControlView}
                      iconToggle={!showSpouses}
                      onClick={handleToggle}
                    />
                  )}
                </>
              }
            >
              <div className={relationshipWrapperCss} ref={relationshipWrapperRef}>
                <svg className={connectorLines} id="svg-canvas-for-relationship-connector-lines" />
                <Generations
                  showSpouses={showSpouses}
                  relatedThroughInitialSpouse={relatedThroughInitialSpouse}
                  targetPersonIsSpouse={targetPersonIsSpouse}
                  emptyDescendingSide={emptyDescendingSide}
                  preferenceFetched={preferenceFetched}
                  relationshipData={relationshipData}
                  noLinks={noLinks}
                  emptyAscendingSide={emptyAscendingSide}
                  closeRelative={closeRelative}
                />
              </div>
            </ZoomPan>
          )}
          <NoRelationshipDisplay {...props} />
        </div>
      </FullPageOverlay>
    </RelationshipViewerContext.Provider>
  )
}

/**
 * Wrap relationship viewer, and pass in data from useRelationship()
 *
 * @param {object} props - See RelationshipViewer docs.
 * @returns {HTMLElement} - JSX.
 */
function ActiveRelationshipViewer(props = {}) {
  const { fromId, toId, relationshipIdType, eventInfo, friendRelationship, hidePortraits } = props

  // relationshipData is not a path, but gives us back a list of generations starting with the apex, or common ancestor node
  const relationshipData = useRelationship({
    relationshipType: relationshipIdType,
    toId,
    fromId,
    eventInfo,
    friendRelationship,
    hidePortraits,
  })

  return <PassiveRelationshipViewer {...props} relationshipData={relationshipData} />
}

/**
 * JSX relationship viewer.
 *
 * @param {object} props - The props passed into the element.
 * @param {string} [props.fromId] - The ID of the person to route from. Currently not passed in, until support is added for any-tree-person-to-any-other-tree-person relationships (NOT YET IMPLEMENTED).
 * @param {string} [props.toId] - The ID of the person to route to.
 * @param {string} [props.relationshipIdType] - The type of ID for the relationship.
 * @param {boolean} [props.friendRelationship] - Whether this is a friendRelationship. Currently requires a cisId.
 * @param {object} [props.overlay] - useOverlay hook results
 * @param {object} [props.eventInfo] - The event specific information for use at RootsTech or other relatives around me events.
 * @param {boolean} [props.disallowSpouses] - Disallow showing of spouse information for greater privacy.
 * @param {object|null} [props.relationshipData] - Passed-in data from useRelationship(). If not supplied, the component will fetch it's own data.
 * @returns {HTMLElement} - JSX.
 */
export default function RelationshipViewer({ relationshipData, ...props } = {}) {
  // null implies the consumer is using the hook external to the component
  if (relationshipData || relationshipData === null) {
    return <PassiveRelationshipViewer {...props} relationshipData={relationshipData} />
  }
  return <ActiveRelationshipViewer {...props} />
}

function Generations({
  showSpouses,
  relatedThroughInitialSpouse,
  targetPersonIsSpouse,
  emptyDescendingSide,
  preferenceFetched,
  relationshipData,
  noLinks,
  emptyAscendingSide,
  closeRelative,
}) {
  const apexGeneration = relationshipData?.generations?.find((gen) => gen?.apex) || relationshipData?.generations[0]

  const ascendingGenerations = relationshipData?.generations?.filter((gen) => gen.ascendingSide)?.reverse()
  const descendingGenerations = relationshipData?.generations?.filter((gen) => gen.descendingSide)

  return (
    <div
      className={generationsWrapper}
      show-spouses={boolAttr(showSpouses)}
      related-through-initial-spouse={boolAttr(relatedThroughInitialSpouse)}
      target-person-is-spouse={boolAttr(targetPersonIsSpouse)}
      empty-descending-side={boolAttr(emptyDescendingSide)}
      style={{
        '--generations-grid-columns': closeRelative || emptyDescendingSide || emptyAscendingSide ? 1 : 'repeat(2, 1fr)',
        '--generations-grid-gap': `20px ${apexGeneration ? personNodeWidth : 0}px`,
      }}
    >
      {preferenceFetched && (
        <div className={gridCss}>
          {/* See Readme for glossary of terms */}
          {/** ascending generations */}
          {!emptyAscendingSide &&
            ascendingGenerations?.map((generation, i) => {
              const previousPersonDetails = ascendingGenerations[i - 1]?.ascendingSide?.person.nameConclusion.details
              const relationshipName =
                i > 0 ? previousPersonDetails?.fullText || previousPersonDetails?.nameForms[0].givenPart : null

              return (
                <div
                  key={`gen_${generation.index}`}
                  data-testid={`generation_${generation.index}`}
                  className={generationsCss}
                  style={{ gridColumn: 1, gridRow: ascendingGenerations.length - i + 1 }}
                >
                  <RelationshipViewerCouple
                    couple={generation.ascendingSide}
                    showCoParents={showSpouses}
                    targetPersonIsSpouse={targetPersonIsSpouse}
                    type="ascending"
                    initialGeneration={generation.initialGeneration}
                    displayMonogram={generation.initialGeneration && relationshipData.displayMonogram}
                    noLinks={noLinks}
                    relationshipName={relationshipName}
                  />
                </div>
              )
            })}
          {/** apex generation */}
          {apexGeneration && (
            <div
              key={`gen_${apexGeneration.index}`}
              data-testid={`generation_${apexGeneration.index}`}
              className={generationsCss}
              style={{
                gridColumn: closeRelative || emptyDescendingSide || emptyAscendingSide ? 1 : '1 / span 2',
                gridRow: 1,
              }}
            >
              <RelationshipViewerCouple
                couple={apexGeneration.apex}
                showCoParents={showSpouses}
                targetPersonIsSpouse={targetPersonIsSpouse}
                finalGeneration={apexGeneration.finalGeneration}
                type="apex"
                noLinks={noLinks}
                relationshipName={apexGeneration.apex?.person.nameConclusion.details.fullText}
              />
            </div>
          )}
          {/** descending generations */}
          {!emptyDescendingSide &&
            descendingGenerations?.map((generation, i) => {
              const previousPersonDetails =
                i === 0
                  ? apexGeneration.apex?.person.nameConclusion.details
                  : descendingGenerations[i - 1]?.descendingSide?.person.nameConclusion.details

              const relationshipName = previousPersonDetails?.fullText || previousPersonDetails?.nameForms[0].givenPart

              return (
                <div
                  key={`gen_${generation.index}`}
                  data-testid={`generation_${generation.index}`}
                  className={generationsCss}
                  style={{ gridColumn: emptyAscendingSide ? 1 : 2, gridRow: i + 2 }}
                >
                  <RelationshipViewerCouple
                    couple={generation.descendingSide}
                    showCoParents={showSpouses}
                    targetPersonIsSpouse={targetPersonIsSpouse}
                    type="descending"
                    finalGeneration={generation.finalGeneration}
                    displayMonogram={generation.finalGeneration && relationshipData.displayMonogram}
                    noLinks={noLinks}
                    relationshipName={relationshipName}
                  />
                </div>
              )
            })}
        </div>
      )}
    </div>
  )
}
