import React, { useState, useEffect } from 'react'
import { css } from '@linaria/core'
import { Paragraph, Card, PersonBlock, H5, colors } from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import { Person } from '@fs/zion-person'
import { useUser, fetchContactByCisId } from '@fs/zion-user'
import { useTranslation, Trans } from 'react-i18next'

// curve radius
const cr = 8
const apexLineHeight = 27
const containerPaddingTop = 20
// middle line height
const mh = 11
// bottom line height
const bh = 45

const startingY = 95
const middleY = startingY + cr + mh + apexLineHeight
const bottomY = middleY + 50

const gap = 4

const centeredTextStuff = css`
  text-align: center;
`

const svgCss = css`
  position: absolute;
  direction: ltr; /* Force LTR to prevent unnecessary shift on RTL */
  inset-inline-start: 0;
  top: 0;
  stroke: black;
  overflow: visible;
  stroke-dasharray: 4px;
  fill: none;
`

const personWrapCss = css`
  --person-horizontal-adjust: -49px;
  --bottom-person-position: ${bottomY + bh + gap}px;
  --middle-person-position: ${middleY + gap}px;

  position: absolute;
  top: 0;
  max-width: 135px;
  &[apex] {
    inset-inline-start: 70px;
    background-color: ${colors.gray03};
  }
  &[middle-left] {
    top: var(--middle-person-position);
    inset-inline-start: -14.5px;
  }
  &[middle-right] {
    inset-inline-end: -16.5px;
    top: var(--middle-person-position);
  }
  &[bottom-left] {
    inset-inline-start: -46px;
    width: 135px;
    top: var(--bottom-person-position);
  }
  &[bottom-right] {
    inset-inline-end: -49px;
    width: 135px;
    top: var(--bottom-person-position);
  }
`
const noRelationshipTreeCss = css`
  position: relative;
  margin-top: 20px;
  width: 270px;
`
const containerCss = css`
  display: flex;
  align-items: center;
  flex-direction: column;
  padding: ${containerPaddingTop}px;
`

const NoRelationshipDisplay = ({ relationshipData, toId, relationshipTitle, relationshipIdType, noLinks }) => {
  const { personId, userLoading } = useUser()
  const [otherPerson, setOtherPerson] = useState()
  const isCisId = relationshipIdType === 'cisId'

  useEffect(() => {
    let mounted = true
    if (relationshipIdType === 'cisId') {
      fetchContactByCisId(toId).then((data) => {
        mounted && setOtherPerson(data)
      })
    }
    return () => {
      mounted = false
    }
  }, [relationshipIdType, toId])
  const { t } = useTranslation()
  const errorWithRelationshipDescription = t('relationship-viewer.error-getting-relationship-description')
  const userHasNotOptedInDescription = t('relationship-viewer.user-has-not-opted-in-description')
  const relationshipUnknown = t('relationship-viewer.relationship-unknown')
  const { userHasNotOptedIn, noRelationship, errorWithRelationship } = relationshipData || {}
  if (!relationshipData || (!userHasNotOptedIn && !noRelationship && !errorWithRelationship)) return null
  const sharedBlockProps = {
    avatarProps: { sex: 'unknown', size: 'sm' },
    size: 'md',
    centered: true,
    name: '',
  }
  return (
    (userHasNotOptedIn || noRelationship || errorWithRelationship) && (
      <div className={containerCss}>
        <div style={{ maxWidth: '680px' }}>
          <Card>
            <div className={centeredTextStuff}>
              <H5 centered>{relationshipTitle}</H5>
              {noRelationship && <H5>{relationshipUnknown}</H5>}
              <Paragraph size="sm">
                {/* user has not opted in to share relationship info error message */}
                {userHasNotOptedIn && userHasNotOptedInDescription}
                {/* No relationship found message */}
                {noRelationship && (
                  <Trans i18nKey="relationship-viewer.no-relationship-found-description">
                    <Link
                      target="_blank"
                      external
                      to="https://www.familysearch.org/help/helpcenter/article/relationship-unknown"
                    />
                  </Trans>
                )}
                {/* error message */}
                {errorWithRelationship && !userHasNotOptedIn && errorWithRelationshipDescription}
              </Paragraph>
            </div>
          </Card>
        </div>
        {relationshipIdType !== 'contributorId' && (
          <div className={noRelationshipTreeCss}>
            <svg className={svgCss}>
              <path
                d={`M 136 ${startingY}, v${apexLineHeight}, M 21 ${middleY}, v-${mh} a${cr},-${cr} 0 0 1 ${cr}, -${cr} h213, a${cr},${cr} 0 0 1 ${cr}, ${cr}, v${mh} M21 ${bottomY} v${bh} M 250 ${bottomY} v${bh}`}
              />
            </svg>
            <div apex="" className={personWrapCss}>
              <PersonBlock {...sharedBlockProps} name={t('relationship-viewer.shared-relative')} />
            </div>
            <div middle-left="" className={personWrapCss}>
              <PersonBlock {...sharedBlockProps} />
            </div>
            <div middle-right="" className={personWrapCss}>
              <PersonBlock {...sharedBlockProps} />
            </div>
            <div bottom-left="" className={personWrapCss}>
              <Person
                personId={personId}
                loading={userLoading}
                overline={t('relationship-viewer.you')}
                orientation="portrait"
                componentSize="md"
                openPersonOverlay={!noLinks}
                doNotLinkToPersonPage={noLinks}
              />
            </div>
            <div bottom-right="" className={personWrapCss}>
              {isCisId ? (
                <PersonBlock
                  centered
                  size="md"
                  overline={t('relationship-viewer.relationship-unknown')}
                  avatarProps={{ monogram: otherPerson?.contactName }}
                  name={otherPerson?.contactName}
                />
              ) : (
                <Person
                  personId={toId}
                  overline={t('relationship-viewer.relationship-unknown')}
                  orientation="portrait"
                  componentSize="md"
                  openPersonOverlay={!noLinks}
                  doNotLinkToPersonPage={noLinks}
                />
              )}
            </div>
          </div>
        )}
      </div>
    )
  )
}

export default NoRelationshipDisplay
