import React from 'react'
import { css } from '@linaria/core'
import { useTranslation } from 'react-i18next'
import { boolAttr, propsToAttributes } from '@fs/zion-frontend-friends'
import { PersonBlock } from '@fs/zion-ui'
import { Person } from '@fs/zion-person'

export const personNodeWidth = 200 // we use this in RelationshipViewer to handle adding extra padding when related through spouse

const coupleWrapper = css`
  padding: 0 10px;
  position: relative;
  width: ${personNodeWidth}px;
  display: flex;
  flex-flow: row;
  justify-content: space-around;

  &[showcoparents] {
    width: ${personNodeWidth * 2}px;
  }

  /* The ascending and descending side may be related through different spouses, so apex may be wider than standard, but spouses always show in the apex */
  &[type='apex'] {
    margin: 0 auto;
    min-width: ${personNodeWidth * 2}px;
    max-width: ${personNodeWidth * 3}px;
    width: fit-content;
  }

  /* Handle showing a spouse that we are related to when other spouses are not showing */
  &[coparentistargetperson]:not([showcoparents]) {
    position: relative;
  }
`

const placeholderSpouse = css`
  width: ${personNodeWidth}px;
  min-width: ${personNodeWidth}px;
  padding: 10px 20px;
  opacity: 0.5;
`

const personWrapper = css`
  padding: 0 10px;
  display: inline-block;
  width: ${personNodeWidth}px;
  min-width: ${personNodeWidth}px;
  max-width: ${personNodeWidth}px;

  /* Ensure that entire persons appear as clickable. Caveat: If no relationship is found, or there is an error, isprivate does not get set because we are missing *all* of the data. */
  &:not([isprivate]) {
    cursor: pointer;
  }

  /* Handle showing a spouse that we are related to when other spouses are not showing by positioning it absolutely - RelationshipViewer adds extra padding to handle this as well */
  &[coparentistargetperson]:not([showcoparents])[targetperson],
    /* Also do this for when we are related through our own spouse, but we'll need to change right to left */
    &[coparentispathperson]:not([showcoparents])[initial],
    /* Continue positioning absolutely at the apex node even if co-parents are showing so that the ascending side will line up where it is supposed to */
    [type='apex'] &[coparentistargetperson][showcoparents][targetperson] {
    position: absolute;
    inset-inline-end: -${personNodeWidth}px;
  }
  &[coparentispathperson]:not([showcoparents])[initial] {
    inset-inline-start: -${personNodeWidth}px;
  }
  & [data-testid='person'] {
    max-width: fit-content;
    margin: 0 auto;
    padding: 10px;
  }

  /* make apex persons display next to each other, except when showing spouses - when showing spouses set to the standard spacing */
  [type='apex'] &[inpath][apexpersononleft]:not([showcoparents]) [data-testid='person'],
  [type='apex'] &[coparent][apexpersononright]:not([showcoparents]) [data-testid='person'],
  [type='apex'] &[sourcecoparent] [data-testid='person'] {
    margin-inline-end: 0;
  }
  /* handle special case for when the target person is a spouse of the apex person */
  [type='apex'] &[inpath]:not([showcoparents])[coparentistargetperson] [data-testid='person'],
  [type='apex'] &[inpath][apexpersononright]:not([showcoparents]) [data-testid='person'],
  [type='apex'] &[coparent][apexpersononleft]:not([showcoparents]) [data-testid='person'],
  [type='apex'] &[destcoparent] [data-testid='person'] {
    margin-inline-start: 0;
  }
  /* handle special cases for when the target person is a spouse of the apex person */
  [type='apex'] &[inpath][showcoparents][coparentistargetperson] [data-testid='person'],
  [type='apex'] &[sourcecoparent][showcoparents][coparentistargetperson] [data-testid='person'] {
    margin: 0 auto;
  }

  [data-testid='couple-wrapper']:not([type='apex']) &:not([inpath]) [data-testid='person'] {
    opacity: 0.5;
  }
`

// possible values for overlineKey, which come from the endpoint for relationship descriptions:
const relationshipToPreviousKeyMap = {
  MOTHER: 'relationship-viewer.relationship-to-previous-person.MOTHER.label',
  FATHER: 'relationship-viewer.relationship-to-previous-person.FATHER.label',
  SON: 'relationship-viewer.relationship-to-previous-person.SON.label',
  DAUGHTER: 'relationship-viewer.relationship-to-previous-person.DAUGHTER.label',
  CHILD: 'relationship-viewer.relationship-to-previous-person.CHILD.label',
  PARENT: 'relationship-viewer.relationship-to-previous-person.PARENT.label',
  WIFE: 'relationship-viewer.relationship-to-previous-person.WIFE.label',
  HUSBAND: 'relationship-viewer.relationship-to-previous-person.HUSBAND.label',
  ME: 'relationship-viewer.relationship-to-previous-person.ME.label',
  CLOSE_RELATIONSHIP: 'relationship-viewer.relationship-to-previous-person.CLOSE_RELATIONSHIP.label',
}

/**
 * JSX relationship person.
 * We put persons into a wrapper, so that we can also use human-understandable handles for positioning and drawing lines.
 *
 * @param {object} props - The props passed into the element.
 * @returns {HTMLElement} - JSX.
 */
const PersonWrapper = (props = {}) => {
  const [t] = useTranslation()
  /* See Readme for glossary of terms */
  const propsToReflect = [
    /* Do not stop reflecting these props unless they are both not used in the css in this file and also are not used in RelationshipViewerD3 to draw lines */
    'inPath', // used in RelationshipViewerD3
    'coParent', // used in RelationshipViewerD3
    'destCoParent', // used in RelationshipViewerD3
    'sourceCoParent', // used in RelationshipViewerD3
    'targetPerson', // used in RelationshipViewerD3
    'initial', // used in RelationshipViewerD3
    'coParentIsPathPerson', // used in RelationshipViewerD3
    'apexPersonOnLeft',
    'apexPersonOnRight',
    'coParentIsTargetPerson',
    'showCoParents',
    'aria-label',
    'isPrivate',
  ]
  const formattedAttrs = propsToAttributes(propsToReflect, props)
  let disableTruncation = false

  const {
    overline,
    overlineKey,
    personObj,
    finalGeneration,
    inPath,
    coParentIsTargetPerson,
    targetPerson,
    initial,
    displayMonogram,
    noLinks,
  } = props
  let testid = 'person-wrapper'
  let avatarSize = 'default'
  if (initial) {
    testid += ' initial'
    avatarSize = 'bigger'
  }
  if (finalGeneration && inPath && (!coParentIsTargetPerson || targetPerson)) {
    // we only disable truncation for target persons who are living. This allows us to show the full contact name, as was requested by rootstech
    disableTruncation = !personObj?.id
    testid += ' target'
    avatarSize = 'bigger'
  }

  // if we don't get an overline key passed in, we already translated it in the parent component
  const overlineToUse = overlineKey ? t(relationshipToPreviousKeyMap[overlineKey]) : overline

  return (
    <div className={personWrapper} {...formattedAttrs} data-testid={testid}>
      <Person
        personObj={{ ...personObj, id: personObj?.id || 'PRIVATE' }} // Passing id='PRIVATE' allows Person to still display nicely while short-circuiting overlays and hiding the non-existent PID
        avatarSize={avatarSize}
        disableTruncation={disableTruncation}
        overline={overlineToUse}
        orientation="portrait"
        openPersonOverlay={!noLinks}
        doNotLinkToPersonPage={noLinks}
        componentSize="md"
        displayMonogram={displayMonogram}
        linksOpenNewTab
      />
    </div>
  )
}

const relationshipToPreviousWithNameKeyMap = {
  MOTHER: 'relationship-viewer.relationship-to-previous-person.MOTHER-of.label',
  FATHER: 'relationship-viewer.relationship-to-previous-person.FATHER-of.label',
  SON: 'relationship-viewer.relationship-to-previous-person.SON-of.label',
  DAUGHTER: 'relationship-viewer.relationship-to-previous-person.DAUGHTER-of.label',
  CHILD: 'relationship-viewer.relationship-to-previous-person.CHILD-of.label',
  PARENT: 'relationship-viewer.relationship-to-previous-person.PARENT-of.label',
  WIFE: 'relationship-viewer.relationship-to-previous-person.WIFE-of.label',
  HUSBAND: 'relationship-viewer.relationship-to-previous-person.HUSBAND-of.label',
  SPOUSE: 'relationship-viewer.relationship-to-previous-person.SPOUSE-of.label',
  CLOSE_RELATIONSHIP: 'relationship-viewer.relationship-to-previous-person.CLOSE_RELATIONSHIP-of.label',
}

/**
 * JSX relationship couple.
 *
 * @param {object} props - The props passed into the element.
 * @param {object} [props.couple] - The couple to display.
 * @param {boolean} [props.showCoParents] - Whether to show related spouses for individuals who are part of the direct-line relationship.
 * @param {string} [props.type] - The type of couple to display "ascending"|"descending"|"apex".
 * @returns {HTMLElement} - JSX.
 */
export default function RelationshipViewerCouple(props = {}) {
  const { couple, type, showCoParents, finalGeneration, displayMonogram, noLinks, relationshipName } = props
  const [t] = useTranslation()

  // add placeholder data for single parents in the apex node except for in the case of a relationship to self
  const placeHolderPerson = {
    relationshipToPreviousDescription: t('relationship-viewer.relationship-to-previous-person.PARENT.label'),
    relationshipToPrevious: 'PARENT',
  }
  /* See Readme for glossary of terms */
  if (type === 'apex' && couple && !(finalGeneration && couple.indexInPath === 0)) {
    // if we are related through spouse at the apex, then we could have a coParent and sourceCoParent, so we don't want to add placeholder in that case
    if (!couple.coParent && (couple.sourceCoParent || couple.destCoParent)) {
      couple.sourceCoParent = couple.sourceCoParent || placeHolderPerson
      couple.destCoParent = couple.destCoParent || placeHolderPerson
    } else {
      couple.coParent = couple.coParent || placeHolderPerson
    }
  }

  // when there is a single spouse at the apex, whether the path person is on the left or right is used for removing the extra left and right margins from the correct people when we are not displaying spouses so they will just be as close together as they can be.
  const apexPersonHasCoParentToDisplay = type === 'apex' && couple && couple.coParent && !couple.coParentIsTargetPerson
  const apexPersonOnRight = apexPersonHasCoParentToDisplay && couple.person.gender === 'FEMALE'
  const apexPersonOnLeft = apexPersonHasCoParentToDisplay && couple.person.gender === 'MALE'

  const commonPersonWrapperProps = {
    apexPersonOnLeft,
    apexPersonOnRight,
    coParentIsTargetPerson: couple?.coParentIsTargetPerson,
    displayMonogram,
    finalGeneration,
    isPrivate: !couple?.person?.id,
    showCoParents,
  }

  let ariaLabelText
  let ariaLabelTextCoParent

  if (relationshipName) {
    if (couple?.person?.relationshipToPrevious) {
      ariaLabelText =
        type === 'apex'
          ? `${t('relationship-viewer.relationship-to-previous-person.common.ancestor')} ${relationshipName}`
          : t(relationshipToPreviousWithNameKeyMap[couple.person.relationshipToPrevious], {
              previousName: relationshipName,
            })
    }
    if (
      couple?.coParent &&
      couple?.coParent?.nameConclusion?.details?.fullText &&
      couple?.coParent?.relationshipToPrevious
    ) {
      ariaLabelTextCoParent =
        type === 'apex'
          ? `${t('relationship-viewer.relationship-to-previous-person.common.ancestor')} ${couple?.coParent?.nameConclusion.details.fullText}`
          : t(relationshipToPreviousWithNameKeyMap[couple.coParent.relationshipToPrevious], {
              previousName: couple.person.nameConclusion.details.fullText,
            })
    }
  }

  return (
    <div
      data-testid="couple-wrapper"
      className={coupleWrapper}
      type={type} // this prop is used in RelationshipViewerD3 to draw the lines
      showcoparents={boolAttr(showCoParents)}
      coparentispathperson={boolAttr(couple?.coParentIsPathPerson)}
      coparentistargetperson={boolAttr(couple?.coParentIsTargetPerson)}
    >
      {couple && (
        <>
          {/*  Source coparent in apex */}
          {couple.sourceCoParent && type === 'apex' && (
            <PersonWrapper
              {...commonPersonWrapperProps}
              overlineKey={couple.sourceCoParent.relationshipToPrevious}
              overline={couple.sourceCoParent.relationshipToPreviousDescription}
              personObj={couple.sourceCoParent}
              sourceCoParent
              noLinks={noLinks}
            />
          )}
          {/* coparent for female persons in path */}
          {couple.coParent &&
            (showCoParents || type === 'apex') &&
            !couple.coParentIsTargetPerson &&
            !couple.coParentIsPathPerson &&
            couple.person.gender === 'FEMALE' && (
              <PersonWrapper
                {...commonPersonWrapperProps}
                overlineKey={couple.coParent.relationshipToPrevious}
                overline={couple.coParent.relationshipToPreviousDescription}
                personObj={couple.coParent}
                coParent
                noLinks={noLinks}
                aria-label={ariaLabelTextCoParent}
              />
            )}
          {/* coparent placeholder for female persons in path */}
          {showCoParents &&
            !couple.coParent &&
            type !== 'apex' &&
            couple.person.gender === 'FEMALE' &&
            couple.person.id !== 'PRIVATE' &&
            couple.indexInPath !== 0 &&
            !finalGeneration && (
              <div className={placeholderSpouse}>
                <PersonBlock
                  centered
                  overline={t('relationship-viewer.no-spouse-placeholder-label')}
                  name=" "
                  avatarProps={{ sex: 'male' }}
                  size="md"
                />
              </div>
            )}
          {/* ALWAYS SHOWN: common ancestor or person in path in apex */}
          <PersonWrapper
            {...commonPersonWrapperProps}
            overlineKey={couple?.person?.relationshipToPrevious}
            overline={couple?.person?.relationshipToPreviousDescription}
            personObj={couple?.person}
            inPath
            initial={couple.indexInPath === 0}
            coParentIsPathPerson={couple.coParentIsPathPerson}
            noLinks={noLinks}
            aria-label={ariaLabelText}
          />
          {/* If you are related through the spouse, meaning the spouse is in the path, we always need to display the spouse, regardless of the display option for showing coParents - we also always want this going out to the right */}
          {couple.coParent && (couple.coParentIsTargetPerson || couple.coParentIsPathPerson) && (
            <PersonWrapper
              {...commonPersonWrapperProps}
              overlineKey={couple.coParent.relationshipToPrevious}
              overline={couple.coParent.relationshipToPreviousDescription}
              personObj={couple.coParent}
              inPath
              targetPerson={couple.coParentIsTargetPerson}
              noLinks={noLinks}
            />
          )}
          {/* coparent placeholder for male persons in path */}
          {showCoParents &&
            !couple.coParent &&
            type !== 'apex' &&
            couple.person.gender === 'MALE' &&
            couple.person.id !== 'PRIVATE' &&
            couple.indexInPath !== 0 &&
            !finalGeneration && (
              <div className={placeholderSpouse}>
                <PersonBlock
                  centered
                  overline={t('relationship-viewer.no-spouse-placeholder-label')}
                  name=" "
                  avatarProps={{ sex: 'female' }}
                  size="md"
                />
              </div>
            )}
          {/* coparent for male persons in path */}
          {couple.coParent &&
            (showCoParents || type === 'apex') &&
            !couple.coParentIsTargetPerson &&
            !couple.coParentIsPathPerson &&
            couple.person.gender === 'MALE' && (
              <PersonWrapper
                {...commonPersonWrapperProps}
                overlineKey={couple.coParent.relationshipToPrevious}
                overline={couple.coParent.relationshipToPreviousDescription}
                personObj={couple.coParent}
                coParent
                noLinks={noLinks}
                aria-label={ariaLabelTextCoParent}
              />
            )}
          {/*  Dest coparent in apex */}
          {couple.destCoParent && type === 'apex' && (
            <PersonWrapper
              {...commonPersonWrapperProps}
              overlineKey={couple.destCoParent.relationshipToPrevious}
              overline={couple.destCoParent.relationshipToPreviousDescription}
              personObj={couple.destCoParent}
              destCoParent
              noLinks={noLinks}
            />
          )}
        </>
      )}
    </div>
  )
}
